;(function(){System.register([],function(exports,module){'use strict';return{execute:function(){(Drupal2=>{const odsFooter={constants:{mobileBreakpoint:768},methods:{initialize:()=>{odsFooter.methods.initializeCookiePrivacy();if(window.innerWidth>odsFooter.constants.mobileBreakpoint){return;}[...document.querySelectorAll("li[data-button-menu]")].forEach(item=>{const titles=item.querySelectorAll("span[data-title-menu]");const links=item.querySelectorAll("li.ods-footer__menu__item");if(links){[...titles].forEach(title=>title.classList.add("chevron"));}if(!item.hasChildNodes()){return;}item.addEventListener("click",()=>{const block=item.querySelector(".ods-footer__menu__item__block");if(!block){return;}if(block.children[1].className==="d-none d-md-block"&&links){block.children[1].classList.remove("d-none","d-md-block");[...titles].forEach(title=>title.classList.add("open"));}else{block.children[1].classList.add("d-none","d-md-block");[...titles].forEach(title=>title.classList.remove("open"));}});});},// see DTPROJ-11896 to use this feature
initializeCookiePrivacy:()=>{const cookieLink=document.querySelector('[data-tc-clic="footer::bottom::js-cookie-privacy"]');if(cookieLink){cookieLink.addEventListener("click",e=>{e.preventDefault();e.stopPropagation();if(window.tC){window.tC.privacyCenter.showPrivacyCenter();}});}}},attach:()=>{odsFooter.methods.initialize();}};Drupal2.behaviors.odsFooter=odsFooter;})(Drupal);}};});})();
